import React, { useEffect, useState } from "react";
import {
  getMicrosoftMalwareLatest,
  getMicrosoftMalwareStatus,
  inferMicrosoftMalwareDataset,
  trainMicrosoftMalwareModel,
  lookupMalwareHash,
} from "../../api/mlApi";
import "./IntegrityVerification.css";

function MicrosoftMalware() {
  const [status, setStatus] = useState(null);
  const [preds, setPreds] = useState([]);
  const [error, setError] = useState(null);
  const [isTraining, setIsTraining] = useState(false);
  const [isRunning, setIsRunning] = useState(false);
  const [lookupHash, setLookupHash] = useState("sha256:d5ce4f63b42eb61f7f6d7f8ad86cb6f7f90fca4f67f6bca3de91ef6b4f4f7f31");
  const [lookupPackage, setLookupPackage] = useState("xmrig-wrapper");
  const [lookupVersion, setLookupVersion] = useState("1.0.0");
  const [lookupResult, setLookupResult] = useState(null);
  const [isLookupRunning, setIsLookupRunning] = useState(false);

  const loadStatus = async () => {
    const s = await getMicrosoftMalwareStatus();
    setStatus(s);
  };

  const loadLatest = async () => {
    const res = await getMicrosoftMalwareLatest();
    setPreds(res.predictions || []);
  };

  useEffect(() => {
    (async () => {
      try {
        await loadStatus();
        await loadLatest();
        setError(null);
      } catch (e) {
        setError(e.message);
      }
    })();
  }, []);

  const handleTrain = async () => {
    setIsTraining(true);
    try {
      setError(null);
      await trainMicrosoftMalwareModel(10000);
      await loadStatus();
    } catch (e) {
      setError(e.message);
    } finally {
      setIsTraining(false);
    }
  };

  const handleRun = async () => {
    setIsRunning(true);
    try {
      setError(null);
      await inferMicrosoftMalwareDataset(300, true);
      await loadLatest();
      await loadStatus();
    } catch (e) {
      setError(e.message);
    } finally {
      setIsRunning(false);
    }
  };

  const handleLookup = async () => {
    setIsLookupRunning(true);
    try {
      setError(null);
      const res = await lookupMalwareHash(lookupHash, lookupPackage, lookupVersion, "npm");
      setLookupResult(res);
    } catch (e) {
      setError(e.message);
    } finally {
      setIsLookupRunning(false);
    }
  };

  const metrics = status && status.training_state && status.training_state.metrics ? status.training_state.metrics : null;

  return (
    <div className="malware-classification-card">
      <div className="hash-header">
        <div>
          <h3>Microsoft Malware Classification</h3>
          <p className="hash-subtitle">Train and classify malware families from static feature vectors</p>
        </div>
        <div style={{ display: "flex", gap: 10, flexWrap: "wrap" }}>
          <button className="generate-sbom-button" onClick={handleTrain} disabled={isTraining}>
            {isTraining ? "Training..." : "Train Model"}
          </button>
          <button className="generate-sbom-button" onClick={handleRun} disabled={isRunning}>
            {isRunning ? "Running..." : "Run Inference"}
          </button>
          <button className="generate-sbom-button" onClick={loadLatest}>
            Refresh
          </button>
        </div>
      </div>

      {error && <div className="no-evidence">{error}</div>}

      <div className="hash-stats">
        <div className="hash-stat">
          <span className="stat-label">Model</span>
          <span className={`stat-value ${status && status.model && status.model.is_trained ? "verified" : "pending"}`}>
            {status && status.model ? (status.model.is_trained ? "trained" : "not trained") : "N/A"}
          </span>
        </div>
        <div className="hash-stat">
          <span className="stat-label">Accuracy</span>
          <span className="stat-value">{metrics ? metrics.accuracy.toFixed(4) : "N/A"}</span>
        </div>
        <div className="hash-stat">
          <span className="stat-label">F1</span>
          <span className="stat-value">{metrics ? metrics.f1.toFixed(4) : "N/A"}</span>
        </div>
        <div className="hash-stat">
          <span className="stat-label">Recall</span>
          <span className="stat-value">{metrics ? metrics.recall.toFixed(4) : "N/A"}</span>
        </div>
        <div className="hash-stat">
          <span className="stat-label">Predictions</span>
          <span className="stat-value">{preds.length}</span>
        </div>
      </div>

      <div className="evidence-list">
        {preds.length === 0 ? (
          <div className="no-evidence">No predictions loaded</div>
        ) : (
          preds.slice(0, 50).map((p) => (
            <div key={p.id} className="evidence-item">
              <div className="evidence-header">
                <span className="evidence-type">{p.id}</span>
                <span className="severity-badge severity-high">{Number(p.confidence || 0).toFixed(4)}</span>
              </div>
              <div className="evidence-details">
                {"true_class" in p ? (
                  <div className="detail-row">
                    <span>True</span>
                    <span>{String(p.true_class)}</span>
                  </div>
                ) : null}
                <div className="detail-row">
                  <span>Predicted</span>
                  <span>{String(p.predicted_class)}</span>
                </div>
              </div>
            </div>
          ))
        )}
      </div>

      <div className="sbom-section" style={{ marginTop: 16 }}>
        <h5>SBOM Hash Malware Lookup</h5>
        <div style={{ display: "grid", gap: 10 }}>
          <input value={lookupHash} onChange={(e) => setLookupHash(e.target.value)} placeholder="SHA-256 hash" />
          <input value={lookupPackage} onChange={(e) => setLookupPackage(e.target.value)} placeholder="Package name" />
          <input value={lookupVersion} onChange={(e) => setLookupVersion(e.target.value)} placeholder="Version" />
          <button className="generate-sbom-button" onClick={handleLookup} disabled={isLookupRunning}>
            {isLookupRunning ? "Checking..." : "Lookup Hash"}
          </button>
        </div>
        {lookupResult ? (
          <div className="integrity-info" style={{ marginTop: 10 }}>
            <div className="integrity-item">
              <span>Matched:</span>
              <span>{String(!!lookupResult.matched)}</span>
            </div>
            <div className="integrity-item">
              <span>Family:</span>
              <span>{lookupResult.match ? lookupResult.match.family : "N/A"}</span>
            </div>
            <div className="integrity-item">
              <span>Risk:</span>
              <span>{lookupResult.match ? lookupResult.match.risk : "N/A"}</span>
            </div>
          </div>
        ) : null}
      </div>
    </div>
  );
}

export default MicrosoftMalware;
